SELECT 'ORDER_OFFERS' as section;
SELECT id, order_id, driver_id, status, offered_at, expires_at FROM order_offers ORDER BY id DESC LIMIT 10;

SELECT 'DRIVER_QUEUE' as section;
SELECT * FROM driver_queue ORDER BY position;

